1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const INSURANCE_VALUES: Record<string, number> = {
12	  sword: 1000,
13	  amulet: 600,
14	  staff: 800,
15	  potion: 400,
16	  rune: 250,
17	  moonstone: 250,
18	};
19	
20	const DEDUCTIBLE = 100;
21	
22	const PROCESSING_FEE = 5;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	function basePremium(item: any): number {
34	  return BASE_PREMIUMS[item.type] ?? 0;
35	}
36	
37	const COMPONENT_TYPES = ["rune", "moonstone"];
38	const BLOCK_SIZE = 3;
39	const BLOCK_PREMIUM = 60;
40	
41	function isComponent(item: any): boolean {
42	  return COMPONENT_TYPES.includes(item.type);
43	}
44	
45	function groupByType(items: any[]): Record<string, any[]> {
46	  const result: Record<string, any[]> = {};
47	  for (const item of items) {
48	    if (!result[item.type]) result[item.type] = [];
49	    result[item.type].push(item);
50	  }
51	  return result;
52	}
53	
54	function componentGroupPremium(group: any[]): number {
55	  if (group.length === BLOCK_SIZE) return BLOCK_PREMIUM;
56	  return group.reduce((sum: number, item: any) => sum + basePremium(item), 0);
57	}
58	
59	export function claimOffice(input: any): unknown {
60	  const results = [];
61	  const quoteSteps: any[] = [];
62	  const remainingCaps: Record<number, number> = {};
63	  let quoteCount = 0;
64	  for (const step of input.steps) {
65	    if (step.op === "claim") {
66	      const policyItems = quoteSteps[step.policy];
67	
68	      for (const damage of step.incident.damages) {
69	        if (damage.amount < 0) {
70	          throw new Error("Negative damage amount");
71	        }
72	      }
73	
74	      const damageCounts: Record<string, number> = {};
75	      for (const damage of step.incident.damages) {
76	        damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
77	      }
78	      const policyCounts: Record<string, number> = {};
79	      for (const item of policyItems) {
80	        policyCounts[item.type] = (policyCounts[item.type] ?? 0) + 1;
81	      }
82	      for (const [type, count] of Object.entries(damageCounts)) {
83	        if (count > (policyCounts[type] ?? 0)) {
84	          throw new Error(`Damages exceed policy coverage for type: ${type}`);
85	        }
86	      }
87	
88	      const insuranceSum = policyItems.reduce(
89	        (sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0),
90	        0
91	      );
92	      const cap = 2 * insuranceSum;
93	      if (remainingCaps[step.policy] === undefined) {
94	        remainingCaps[step.policy] = cap;
95	      }
96	      let payout = 0;
97	      for (const damage of step.incident.damages) {
98	        const matchingItem = policyItems.find((item: any) => item.type === damage.itemType);
99	        let reimbursement = damage.amount;
100	        if (matchingItem && matchingItem.enchantment >= 8) {
101	          reimbursement = damage.amount * 0.5;
102	        }
103	        payout += reimbursement - DEDUCTIBLE;
104	      }
105	      if (payout > remainingCaps[step.policy]) {
106	        payout = remainingCaps[step.policy];
107	      }
108	      payout = Math.floor(payout);
109	      remainingCaps[step.policy] -= payout;
110	      results.push({ payout, remainingCap: remainingCaps[step.policy] });
111	      continue;
112	    }
113	
114	    quoteSteps.push(step.items);
115	
116	    validateItemTypes(step.items);
117	
118	    const components = step.items.filter(isComponent);
119	    const nonComponents = step.items.filter((i: any) => !isComponent(i));
120	
121	    let rawPolicyBase = 0;
122	    let itemSpecificSurcharges = 0;
123	
124	    for (const item of nonComponents) {
125	      const base = basePremium(item);
126	      rawPolicyBase += base;
127	      if (item.cursed) {
128	        itemSpecificSurcharges += base * 0.5;
129	      }
130	      if (item.enchantment >= 5) {
131	        itemSpecificSurcharges += base * 0.3;
132	      }
133	    }
134	
135	    for (const group of Object.values(groupByType(components))) {
136	      rawPolicyBase += componentGroupPremium(group);
137	    }
138	
139	    let policyWideModifier = 0;
140	
141	    // First insurance surcharge: 10% of policy base premium (always applies)
142	    policyWideModifier += rawPolicyBase * 0.1;
143	
144	    if (input.customer.yearsWithMHPCO >= 2) {
145	      policyWideModifier -= rawPolicyBase * 0.2;
146	    }
147	
148	    quoteCount++;
149	    if (quoteCount > 1) {
150	      policyWideModifier -= rawPolicyBase * 0.15;
151	    }
152	
153	    const premium = Math.ceil(rawPolicyBase + itemSpecificSurcharges + policyWideModifier + PROCESSING_FEE);
154	
155	    results.push({ premium });
156	  }
157	  return { results };
158	}
